// Function to append data to a socket buffer for IP transmission
int ip_append_data(struct sock *sk, struct msghdr *msg, size_t size,
                   int flags, struct rtable *rt, unsigned int iphlen,
                   struct inet_cmsghdr *cmsg, unsigned char ipproto)
{
    struct sk_buff *skb = NULL;
    struct inet_sock *inet = inet_sk(sk);
    unsigned int maxfraglen;
    int err = 0;

    // Set default fragmentation mode based on flags
    sk_setup_mem_limits(sk);
    maxfraglen = ip_sk_route_frags(sk) ? 0 : mtu_from_rtable(rt) - (iphlen + sizeof(struct tcphdr));

    // Start building the IP datagram
    err = __ip_append_data(sk, iphlen, size, frag_off(flags, 0), maxfraglen,
                           rt, msg->msg_flags & MSG_DONTWAIT, &skb, tcp_header(sk),
                           cmsg ? cork.opt : NULL, ipproto, NULL);
    if (err) {
        ip_flush_pending_frames(sk);
        if (!skb && !(flags & MSG_NOSIGNAL))
            sk_send_sigurg(sk);
    } else if (likely(!skb)) {
        struct dst_entry *dst = &rt->dst;

        if (!(msg->msg_flags & MSG_DONTWAIT) && inet->freebind)
            dst_check_and_drop(dst);
        IP_INC_STATS_BH(sock_net(sk), IPSTATS_MIB_OUTSEGS);
    } else {
        struct dst_entry *dst = skb_dst(skb);
        INET_SETSOCKBUFF(sk, dst);
        IP_ADD_STATS_BH(sock_net(sk), IPSTATS_MIB_FRAGMENTS,
                        atomic_read(&skb_shinfo(skb)->frag_list->truesize));
        IP_INC_STATS_BH(sock_net(sk), IPSTATS_MIB_OUTSEGS);
        IP_INC_STATS_BH(sock_net(sk), IPSTATS_MIB_OUTFRAGMENTS);
    }

    return err ?: tcp_push(sk, flags & ~MSG_MORE, size, tcp_header(sk), mss_from_rtable(rt), 0);
}
