#include <linux/list.h>
#include <linux/spinlock.h>
#include <linux/pm_runtime.h>
#include <linux/usb/ch9.h>

struct dwc3_gadget_ep {
    spinlock_t lock; /* Protects the request list */
    struct list_head requests; /* List of requests in progress */
    struct dwc3 *dwc; /* Pointer to the DWC3 controller */
    struct usb_ep ep; /* USB endpoint structure */
};

void dwc3_gadget_giveback(struct dwc3_ep *dep, struct dwc3_request *req, int status)
{
    unsigned long flags;
    struct dwc3_gadget_ep *dep_gadget = container_of(dep, struct dwc3_gadget_ep, ep);

    spin_lock_irqsave(&dep_gadget->lock, flags);

    if (list_first_entry_or_null(&dep_gadget->requests, struct dwc3_request, list) != req) {
        dev_WARN(dep_gadget->dwc->dev, "%s: request %p is not head of list\n",
                 dep->name, req);
    } else {
        list_del_init(&req->list);
    }

    usb_gadget_unmap_request_by_dev(&dep_gadget->dwc->gadget.dev, &req->req);

    /* If request is not cancelled, call completion handler */
    if (status != -ECONNRESET && status != -ESHUTDOWN && req->req.complete) {
        req->req.status = status;
        spin_unlock(&dep_gadget->lock);
        usb_gadget_handle_request(&dep_gadget->ep, &req->req);
        spin_lock(&dep_gadget->lock);
    }

    pm_runtime_mark_last_busy(dep_gadget->dwc->dev);
    pm_runtime_put_autosuspend(dep_gadget->dwc->dev);

    spin_unlock_irqrestore(&dep_gadget->lock, flags);
}
```

In this solution, we first acquire a spin lock to ensure thread safety when manipulating the request list. We then check if the request to be completed is indeed at the head of the list. If it's not, we log a warning. After safely removing the request from the list, we unmap it using `usb_gadget_unmap_request_by_dev`. If the request is not cancelled or shut down, we set its status and call its completion handler. Finally, we manage runtime power by marking the last busy time and putting the device into autosuspend mode. This ensures efficient resource management during USB gadget operations.

