#include <iostream>
#include <regex>
#include <string>
#include <vector>
#include <unordered_map>
#include <optional>

// Define structures and constants for clarity
struct Node {
    std::string type;
    std::string host;
    int port;
    std::string path;
    bool isSubscriptionNode;
};

struct SubscriptionData {
    std::unordered_map<std::string, std::vector<std::string>> excludedNodes;
};

class NetworkManager {
public:
    NetworkManager(const SubscriptionData& subData) : subscriptionData(subData) {}

    void addNodes(const std::string& link, std::vector<Node>& nodes) {
        std::smatch match;
        std::regex re(R"((socks|http)://([^:/]+)(?::(\d+))?(?:/([^?#]*))?)(?:\?(.*))?");

        if (!std::regex_match(link, match, re)) {
            logError("Invalid link format: " + link);
            return;
        }

        Node newNode;
        newNode.type = match.str(1);
        newNode.host = match.str(2);
        newNode.port = match.str(3).empty() ? 80 : std::stoi(match.str(3));
        newNode.path = match.str(4);
        newNode.isSubscriptionNode = isNodeExcluded(link);

        if (newNode.type == "socks") {
            nodes.push_back(newNode);
        } else if (!newNode.path.empty() && newNode.host == "127.0.0.1") {
            newNode.type = "local";
            nodes.push_back(newNode);
        } else if (!newNode.path.empty() && newNode.host != "127.0.0.1") {
            newNode.type = "http";
            nodes.push_back(newNode);
        }
    }

private:
    SubscriptionData subscriptionData;

    void logError(const std::string& error) {
        std::cerr << "Error: " << error << std::endl;
    }

    bool isNodeExcluded(const std::string& node) {
        // Simplified logic to check if node is excluded based on subscription data
        for (const auto& category : subscriptionData.excludedNodes) {
            if (std::find(category.second.begin(), category.second.end(), node) != category.second.end()) {
                return true;
            }
        }
        return false;
    }
};

// Example usage
int main() {
    SubscriptionData subData = { { "socks", { "socks.example.com" } } };
    NetworkManager manager(subData);
    std::vector<Node> nodes;
    manager.addNodes("socks://socks.example.com:1080", nodes);
    // Further processing or output of nodes
    return 0;
}
