```c
int cifs_insert_smb_ses(struct TCP_Server_Info *server, struct cifs_ses *new_ses)
{
    spin_lock(&server->ses_lock);
    list_for_each_entry(struct cifs_ses, s, &server->smb_ses_list, smb_ses_list) {
        if (strcmp(s->username, new_ses->username) == 0) {
            spin_unlock(&server->ses_lock);
            return -EEXIST; // Session already exists
        }
    }
    list_add(&new_ses->smb_ses_list, &server->smb_ses_list);
    spin_unlock(&server->ses_lock);
    return 0; // Success
}
