static struct slc_dev *slc_bump(const char __user *ubuf, unsigned long count)
{
    struct slc_dev *slc;
    struct sk_buff *skb;
    struct can_frame *cf;
    unsigned long len;
    u32 id;
    int i, res;

    slc = alloc_slc();
    if (!slc)
        return ERR_PTR(-ENOMEM);

    skb = alloc_can_skb(&slc->dev, &cf);
    if (!skb) {
        free_slc(slc);
        return ERR_PTR(-ENOMEM);
    }
    slc->skb = skb;
    len = min(CAN_MAX_DLEN, count - 1);

    if (len < 4 || len > CAN_MAX_DLEN) {
        res = -EINVAL;
        goto err_free_skb;
    }

    if (copy_from_user(ubuf, &id, 4)) {
        res = -EFAULT;
        goto err_free_skb;
    }
    res = kstrtou32_from_user(ubuf + 4, len - 4, 16, &id);
    if (res)
        goto err_free_skb;

    cf->can_id = can_soft_can_id(&slc->dev, id) | CAN_EFF_FLAG;
    if (len > 8)
        res = -EINVAL;
    else {
        cf->len = len - 4;
        for (i = 0; i < cf->len; i++) {
            u8 ch;
            if (copy_from_user(&ch, ubuf + 4 + i * 2 + 2, 1)) {
                res = -EFAULT;
                goto err_free_skb;
            }
            cf->data[i] = hex_to_bin(ch);
        }
        res = can_get_echo_skb(&slc->dev, cf->can_id & CAN_EFF_MASK);
        if (res < 0) {
            dev_err(&slc->dev.dev, "echo_skb failed\n");
            goto err_free_skb;
        }
        *skb_get_tail(skb) = *cf;
        skb_put(skb, sizeof(*cf));
        netif_rx(skb);
        slc->dev.stats.tx_packets++;
    }
    slc->kref.refcount = 1;
    return slc;
err_free_skb:
    kfree_skb(skb);
    free_slc(slc);
    return ERR_PTR(res);
}
