static MemoryRegionSection qemu_iotlb_to_section(MemoryMappingList *list,
                                                  hwaddr addr, hwaddr mask)
{
    MemoryRegionSection sec = memory_region_section_init(&sec, list->address_space,
                                                          addr & mask, ~(mask | addr),
                                                          0, NULL);
    IOMMUTLBEntry iotlb = memory_region_iotlb_lookup(sec.mr, addr, IOMMU_NONE);
    uint64_t iotlb_attrs = iommu_tlb_attrs_to_section_attrs(iotlb.attr);

    sec.offset_within_region = addr & TARGET_PAGE_MASK;
    sec.size = TARGET_PAGE_SIZE - sec.offset_within_region;
    sec.memory_attr = iotlb_attrs;

    if (!memory_region_is_iommu(sec.mr)) {
        hwaddr iotlb_addr = (iotlb.addr & ~mask) | (addr & mask);
        hwaddr iotlb_size = ~mask + 1;

        if (iotlb_size < sec.size) {
            sec.size = iotlb_size;
        }
        memory_region_section_del(&sec);
        memory_region_iommu_map(sec.mr, iotlb_addr, &sec, IOMMU_NONE);
        if (!memory_region_section_is_iommu(&sec)) {
            /* IOMMU mapping failed, fall back to RAM or ROM */
            memory_region_section_init(&sec, list->address_space,
                                      addr & mask, ~(mask | addr),
                                      0, NULL);
        }
    }
    return sec;
