```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <llhttp/llhttp.h>

// Define custom callbacks for llhttp
void on_message_complete(llhttp_t *h) {
    printf("Message complete!\n");
}

void on_header_field(llhttp_t *h, const char *at, size_t length) {
    printf("Header Field: ");
    fwrite(at, 1, length, stdout);
    putchar('\n');
}

// Initialize llhttp parser
llhttp_t* init_parser(llhttp_type_t type) {
    llhttp_t *parser = (llhttp_t*)malloc(sizeof(llhttp_t));
    if (!parser) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }
    llhttp_init(parser, type);
    parser->on_message_complete = on_message_complete;
    parser->on_header_field = on_header_field;
    return parser;
}

// Example usage of the parser
int main() {
    llhttp_t *parser = init_parser(HTTP_BOTH);
    const char *data = "GET / HTTP/1.1\r\nHost: www.example.com\r\n\r\n";
    size_t len = strlen(data);

    int nread = 0;
    while (nread < len) {
        int consumed = llhttp_execute(parser, data + nread, len - nread);
        if (llhttp_get_error(parser)) {
            fprintf(stderr, "Error: %s\n", llhttp_get_error_str(parser));
            free(parser);
            return EXIT_FAILURE;
        }
        nread += consumed;
    }
    free(parser);
    return EXIT_SUCCESS;
}
