#include <linux/scsi/scsi.h> // For SCSI command structures

// Assuming sg_common_write is defined elsewhere and handles actual command execution
static int sg_common_write(struct scsi_device *sdev, struct scsi_cmnd *SCpnt);

ssize_t sg_write(struct file *filp, const char __user *buf, size_t count, loff_t *ppos) {
    struct sg_fd *sfp;
    int ret;

    sfp = filp->private_data;
    if (sfp->detached || !access_ok(buf, count))
        return -EACCES;
    ret = sg_lock_command(sfp, 1);
    if (ret < 0)
        return ret;
    ret = sg_copy_from_user(sfp->cmd, buf, count);
    if (ret < 0) {
        if (ret == -EFAULT)
            sg_unmap_and_chain(sfp, NULL);
        else
            ret = -EFAULT;
        goto err_out;
    } else if (ret > sfp->device->command_size) {
        ret = -EMSGSIZE;
        goto err_out;
    }
    ret = sg_common_write(sfp->device, sfp->cmd);
    if (ret >= 0) {
        sfp->resid = ret;
        ret = count - ret;
    } else if (ret == SCSI_MLQUEUE_DEVICE_BUSY) {
        ret = wait_event_interruptible(sfp->wait, !sg_device_is_busy(sfp));
        if (!ret)
            ret = -EAGAIN;
    }
err_out:
    sg_unlock_command(sfp, 1);
    return ret;
}
