  const int height = MatchingDim(input_shape, 1, output_shape, 1);
  const int width = MatchingDim(input_shape, 2, output_shape, 2);
  const int channels = MatchingDim(input_shape, 3, output_shape, 3);
  const int stride_height = params.stride_height;
  const int stride_width = params.stride_width;
  const int filter_height = params.filter_height;
  const int filter_width = params.filter_width;
  const Padding padding = params.padding;

  // Calculate padding values based on the padding type
  int pad_height, pad_width;
  CalculatePadding(height, filter_height, stride_height, padding, &pad_height,
                    &pad_width);

  for (int b = 0; b < batches; ++b) {
    for (int out_y = 0; out_y < height; ++out_y) {
      for (int out_x = 0; out_x < width; ++out_x) {
        int in_y_origin = out_y * stride_height - pad_height;
        int in_x_origin = out_x * stride_width - pad_width;
        T accum = T();
        int count = 0;
        for (int filter_y = 0; filter_y < filter_height; ++filter_y) {
          for (int filter_x = 0; filter_x < filter_width; ++filter_x) {
            int in_y = in_y_origin + filter_y;
            int in_x = in_x_origin + filter_x;
            if (in_y >= 0 && in_y < input_shape.Dims(1) && in_x >= 0 &&
                in_x < input_shape.Dims(2)) {
              accum += input_data[Offset(input_shape, b, in_y, in_x, channels)];
              ++count;
