// Function to execute a shell in a given directory and environment
int exec_shell(const char *shell, const char *dir, char *const argv[], char *const envp[]) {
    pid_t pid;
    int pipefd[2];
    ssize_t numRead;

    if (socketpair(AF_UNIX, SOCK_STREAM, 0, pipefd) == -1) {
        perror("socketpair");
        return -1;
    }

    pid = fork();
    if (pid == -1) {
        perror("fork");
        close(pipefd[0]);
        close(pipefd[1]);
        return -1;
    } else if (pid == 0) {
        // Child process
        close(pipefd[0]);
        close(STDIN_FILENO);
        if (dup2(pipefd[1], STDOUT_FILENO) != STDOUT_FILENO ||
            dup2(pipefd[1], STDERR_FILENO) != STDERR_FILENO) {
            perror("dup2");
            _exit(EXIT_FAILURE);
        }
        close(pipefd[1]);
        if (chdir(dir) != 0) {
            fprintf(stderr, "Failed to chdir to %s (%s)\n", dir, strerror(errno));
            _exit(EXIT_FAILURE);
        }
        execve(shell, argv, envp);
        perror("execve");
        _exit(EXIT_FAILURE);
    } else {
        // Parent process
        close(pipefd[1]);
        char buffer[1024];
        while ((numRead = read(pipefd[0], buffer, sizeof(buffer) - 1)) > 0) {
            buffer[numRead] = '\0';
            printf("%s", buffer);
        }
        if (numRead == -1) {
            perror("read");
        }
        close(pipefd[0]);
        if (waitpid(pid, NULL, 0) == -1) {
            perror("waitpid");
        }
    }
    return 0;
}
