int spnego_asn1_decode_negTokenInit(const uint8_t *buf, size_t len, gss_OID *proto, gss_OID_set *mechlist, uint8_t **token, size_t *toklen) {
    uint8_t *tok = NULL, *tokend = NULL, *tokstart = NULL;
    ssize_t toklen2;
    int ret = -1;

    tok = der_get_available(buf, len, &toklen2);
    if (!tok || toklen2 < 0 || toklen2 >= len) {
        ret = -1;
        goto out;
    }

    tokend = buf + len;
    tokstart = tok;
    tok = der_get_sequence(tok, tokend - tok, &toklen2);
    if (!tok || toklen2 < 0 || tok + toklen2 != tokend) {
        ret = -1;
        goto out;
    }
    tokend = tok + toklen2;

    tok = der_get_int(tok, tokend - tok, NULL);
    if (!tok || tok >= tokend) {
        ret = -1;
        goto out;
    }
    *proto = GSS_C_NO_OID;

    tok = der_get_generalized_string(tok, tokend - tok, (char **)proto);
    if (!tok || tok >= tokend) {
        gss_release_oid(NULL, proto);
        ret = -1;
        goto out;
    }

    tok = der_get_sequence(tok, tokend - tok, &toklen2);
    if (!tok || toklen2 < 0 || tok + toklen2 > tokend) {
        gss_release_oid(NULL, proto);
        ret = -1;
        goto out;
    }
    *mechlist = GSS_C_NO_OID_SET;
    tokstart = tok;
    while (tok < tokend) {
        if (!gss_release_oid(NULL, mechlist)) {
            gss_release_oid_set(NULL, mechlist);
            *mechlist = GSS_C_NO_OID_SET;
        }
        ret = gss_create_empty_oid_set(minor_status, mechlist);
        if (ret != GSS_S_COMPLETE) {
            ret = -1;
            goto out;
        }
        tok = gss_add_oid_set_member(minor_status, tok, tokstart + toklen2 - (tok - tokstart), mechlist);
        if (GSS_ERROR(ret)) {
            gss_release_oid_set(NULL, mechlist);
            *mechlist = GSS_C_NO_OID_SET;
            ret = -1;
            goto out;
        }
    }
    tok = tokstart + toklen2;

    toklen2 = tokend - tok;
    tok = toklen2 ? xtrymalloc(toklen2) : NULL;
    if (!tok) {
        ret = -1;
        goto out;
