// Define a class to manage a shared resource safely using TensorFlow locks
class SharedResourceManager {
public:
    // Function to safely update the resource
    tensorflow::Status UpdateResource(const tensorflow::StringPiece& key, int new_value) {
        mutex_.Lock();  // Lock the mutex to ensure exclusive access
        TF_RETURN_IF_ERROR(ValidateIndex(key, new_value));  // Validate the index before updating
        resources_[key.as_string()] = new_value;  // Update the resource
        mutex_.Unlock();  // Unlock the mutex after modification
        return tensorflow::Status::OK();  // Return success status
    }

    // Function to safely read the resource
    int ReadResource(const tensorflow::StringPiece& key) const {
        mutex_.Lock();  // Lock the mutex for reading
        auto it = resources_.find(key.as_string());
        int value = it != resources_.end() ? it->second : -1;  // Default value if key not found
        mutex_.Unlock();  // Unlock the mutex after reading
        return value;  // Return the resource value
    }

private:
    mutable tensorflow::mutex mutex_;  // Mutex for thread-safe operations
    std::unordered_map<std::string, int> resources_;  // Shared resource storage

