static void *dma_alloc_from_contiguous(struct device *dev, size_t size,
                                       dma_addr_t *dma_handle, gfp_t gfp)
{
        struct page *page;
        void *cpu_addr;

        WARN_ON((gfp & GFP_DMA32) && !dma_capable(dev, DMA_BIT_MASK(32)));

        page = cma_alloc(dev->cma_area, size >> PAGE_SHIFT, get_order(size),
                         (gfp & GFP_DMA32) ? DMA_BIT_MASK(32) : DMA_BIT_MASK(64));
