        WARN_ON((uintptr_t)cpu_addr & (__alignof__(u64) - 1));
        *dma_handle = dma_map_page(dev, page, 0, size, DMA_BIDIRECTIONAL);
        if (dma_mapping_error(dev, *dma_handle)) {
                __free_pages(page, get_order(size));
                cpu_addr = NULL;
        }
        return cpu_addr;
}
