How can one design a function `strnstrn` in C that mimics the behavior of `strnstr`, but with an additional parameter `end` to limit the search area within a larger string? This function should efficiently find the first occurrence of a substring within a specified range and return a pointer to it or `NULL` if not found.

**Created Answer**:
```c
#include <string.h>

char *strnstrn(const char *haystack, const char *needle, size_t haystack_len, const char *end) {
    size_t needle_len = strlen(needle);
    if (!needle_len) {
        return (char *)haystack;
    }
    if ((haystack + haystack_len) < needle || (haystack + needle_len - 1) > end) {
        return NULL;
    }
    for (char *h = (char *)haystack; h <= ((char *)end - needle_len + 1); h++) {
        if (*h == *needle && !memcmp(h + 1, needle + 1, needle_len - 1)) {
            return h;
        }
    }
    return NULL;
}
```
