#include <linux/spinlock.h>
#include <linux/list.h>
#include <linux/pm_runtime.h>
#include <linux/usb/ch9.h>
#include "dwc3.h"

static void dwc3_gadget_giveback(struct dwc3_ep *dep, struct dwc3_request *req, int status)
{
    struct dwc3_gadget_ep	*dep_gadget;
    unsigned long flags;

    spin_lock_irqsave(&dwc->lock, flags);

    list_del(&req->list);
    req->status = status;

    dep_gadget = dep->ep_gadget;
    if (req->request.complete) {
        dep_gadget->req_running--;
        usb_gadget_unmap_request_by_dev(dep_gadget->gadget->dev.parent,
                &req->request, req->direction);
        spin_unlock(&dwc->lock);
        usb_gadget_giveback_request(&dep_gadget->ep, &req->request);
        spin_lock(&dwc->lock);
        if (req->request.status == -ECONNRESET)
            dep_gadget->stall_pending = false;
    }
    if (!list_empty(&dep->req_queued) && !dep->ep.stalled) {
        struct dwc3_request	*new_req;

        new_req = next_request(&dep->req_queued);
        dwc3_gadget_ep_run_transfer(dep, new_req);
    }
    pm_runtime_put(dwc->dev);
    spin_unlock_irqrestore(&dwc->lock, flags);
}
