// Function to handle script request securely
void handle_script_request(http_request &req, const std::string &filename, bool allow_cgi) {
    lua_State *L = luaL_newstate();
    luaL_openlibs(L);

    // Initialize parameters and cookies
    std::map<std::string, std::string> params;
    req.get_params(params);
    std::map<std::string, std::string> cookies;
    req.get_cookies(cookies);

    // CSRF protection check
    const std::string &csrf_token = req.get_param("csrf_token");
    std::string stored_csrf_token;
    if (!req.get_session_value("csrf_token", stored_csrf_token) ||
        csrf_token.empty() || csrf_token != stored_csrf_token) {
        req.send_error(403, "Forbidden");
        lua_close(L);
        return;
    }

    // Prevent file path injection
    if (!allow_cgi && (filename.find("..") != std::string::npos || filename.find("/") != std::string::npos)) {
        req.send_error(403, "Forbidden");
        lua_close(L);
        return;
    }

    // Process cookies in Lua
    for (const auto &c : cookies) {
        std::string escaped_value = escape_lua_value(c.second);
        if (!lua_utils::push_and_call(L, 1, "cookie_" + c.first, escaped_value)) {
            std::cerr << "Error processing cookie " << c.first << std::endl;
        }
    }

    // Process parameters in Lua
    for (const auto &p : params) {
        std::string escaped_value = escape_lua_value(p.second);
        if (!lua_utils::push_and_call(L, 1, p.first, escaped_value)) {
            std::cerr << "Error processing parameter " << p.first << std::endl;
        }
    }

    // Execute Lua script
    std::string script = read_file(filename);
    if (!lua_utils::execute(L, script.c_str())) {
        req.send_error(500, "Internal Server Error");
    }

    lua_close(L);
}
