class StringCompressor:
    def __init__(self, escape_func):
        self.escape_func = escape_func
        self.buffer = bytearray()

    def compress_and_escape(self, utf8_str):
        last_char = None
        count = 0
        for char in utf8_str:
            if char == last_char:
                count += 1
            else:
                if last_char is not None:
                    self._append_compressed_char(last_char, count)
                last_char = char
                count = 1
        if last_char is not None:
            self._append_compressed_char(last_char, count)
        return self.buffer.decode('utf-8')

