C++: Design a function `decodeRLE` to handle Run-Length Encoding in ZRLE decoding, ensuring that the pixel buffer does not overflow by checking the remaining space before appending decoded data. Provide the function signature and a brief explanation of its parameters.

**Created Answer**:
```cpp
void decodeRLE(rdr::InStream &in, std::vector<uint8_t> &out, int uncompSize, int width, int height, int bytespp, bool littleEndian) {
    int rowLen = width * bytespp;
    uint8_t *row = new uint8_t[rowLen];
    int rowStart = 0;
    while ((in.getUChar() & 0xC0) != 0x80) {  // Continue until a row start marker is found
        in.read(row + rowStart, uncompSize - rowStart);
        rowStart += in.gcount();
        if (rowStart >= uncompSize) {
            throw std::runtime_error("ZRLE: Buffer overflow during RLE decoding");
        }
    }
    int n = uncompSize - rowStart;
    in.read((char *)row, n);
    if (in.gcount() != n) throw std::runtime_error("ZRLE: Incomplete row data");
    uint8_t *outPtr = &out.front();
    while (rowStart < uncompSize) {
        uint8_t *ptr = row;
        int count = *ptr++;
        if (!(count & 0x80)) {  // Literal run
            count++;
            if (rowStart + count * bytespp > uncompSize) {
                throw std::runtime_error("ZRLE: Buffer overflow during RLE literal run");
            }
            memcpy(outPtr, ptr, count * bytespp);
            outPtr += count * bytespp;
            rowStart += count * bytespp;
        } else {  // Copy run
            count = ((count & 0x7F) << 8) | *ptr++;
            count++;
            if (rowStart + bytespp > uncompSize || outPtr + count * bytespp > out.size()) {
                throw std::runtime_error("ZRLE: Buffer overflow during RLE copy run");
            }
            memcpy(outPtr, row, bytespp);
            uint8_t *dst = outPtr + bytespp;
            for (int i = 1; i < count; i++) {
                memcpy(dst, outPtr, bytespp);
                dst += bytespp;
            }
            outPtr += count * bytespp;
            rowStart += bytespp;
        }
    }
    delete[] row;
}
```

In this solution, `decodeRLE` processes RLE-encoded data by alternating between literal and copy operations, ensuring that the output buffer `out` does not exceed its allocated size, thus preventing buffer overflow. The function checks the remaining buffer space before each append operation.

