#include <memory>
#include <string>
#include <vector>

// Define error codes and message types
enum class ErrorCode {
    Success,
    CompressionFailed,
    DecompressionFailed,
    SizeExceeded
};

enum class MessageCompressorId {
    CompressorA,
    CompressorB
};

// Define the message types
using CompressedMessage = std::vector<uint8_t>;
using DecompressedMessage = std::string;

// Forward declaration of MessageCompressor class
class MessageCompressor;

class MessageCompressorManager {
public:
    // Constructor with a compressor factory
    explicit MessageCompressorManager(std::shared_ptr<MessageCompressorFactory> compressorFactory);

    // Destructor
    ~MessageCompressorManager();

    // Function to decompress a message safely
    DecompressedMessageResult decompressMessage(MessageCompressorId compressorId, const CompressedMessage& compressedMessage) const;

    // Function to compress a message safely
    CompressedMessageResult compressMessage(MessageCompressorId compressorId, const DecompressedMessage& message) const;

private:
    std::shared_ptr<MessageCompressorFactory> compressorFactory_; // Factory for creating compressors
};

// Example implementation of MessageCompressorManager
MessageCompressorManager::MessageCompressorManager(std::shared_ptr<MessageCompressorFactory> compressorFactory)
    : compressorFactory_(std::move(compressorFactory)) {}

MessageCompressorManager::~MessageCompressorManager() = default;

DecompressedMessageResult MessageCompressorManager::decompressMessage(MessageCompressorId compressorId, const CompressedMessage& compressedMessage) const {
    auto compressor = compressorFactory_->create(compressorId);
    if (!compressor) {
        return {ErrorCode::CompressionFailed, ""};
    }
    auto result = compressor->decompress(compressedMessage);
    if (!result) {
        return {ErrorCode::DecompressionFailed, ""};
    }
    if (result.value().size() > MaxMessageSizeBytes) {
        return {ErrorCode::SizeExceeded, ""};
    }
    return {ErrorCode::Success, std::move(result.value())};
}

CompressedMessageResult MessageCompressorManager::compressMessage(MessageCompressorId compressorId, const DecompressedMessage& message) const {
    auto compressor = compressorFactory_->create(compressorId);
    if (!compressor) {
        return {ErrorCode::CompressionFailed, {}};
    }
    auto result = compressor->compress(message);
    if (!result || result.value().size() > MaxMessageSizeBytes) {
        return {ErrorCode::SizeExceeded, {}};
    }
    return {ErrorCode::Success, std::move(result.value())};
}
