static void *load_bpf_obj(const char *file_name, size_t *file_size)
{
    struct stat file_stat;
    void *file_data;

    if (stat(file_name, &file_stat) < 0) {
        perror("failed to stat file");
        return NULL;
    }
    if (file_stat.st_size == 0) {
        fprintf(stderr, "file is empty\n");
        return NULL;
    }
