#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <openssl/ssl.h>

#include "nbd-internal.h"
#include "internal.h"

#define MAX_REQUEST_SIZE 1024 * 1024 * 1024

typedef struct {
    // Define the structure for storing server options
} ServerOptions;

typedef struct Server {
    // Define the structure for the server, including TLS context and other data members
    SSL *tls;
    ServerOptions *opts;
    int cancel;
} Server;

static int negotiate_handshake_newstyle_options(Server *s) {
    int ret;
    const char *optname, *optval;

    while ((ret = nbd_negotiate_getopt(s->sockfd, &optname, &optval)) > 0) {
        if (optname[0] == '-' || !strcmp(optname, "exportname")) {
            free(s->opts->export);
            s->opts->export = strdup(optval);
            if (!s->opts->export)
                return -ENOMEM;
        } else if (!strcmp(optname, "size")) {
            s->opts->size = strtoul(optval, NULL, 0);
            if (s->opts->size > MAX_REQUEST_SIZE) {
                error_report("NBD export size too large: %" PRIu64,
                             s->opts->size);
                return -EINVAL;
            }
        } else {
            error_report("NBD option '%s' not supported", optname);
            ret = -EINVAL;
        }
    }
    if (ret < 0)
        return ret;

    if (s->tls) {
        ret = crypto_negotiate_tls(s->sockfd, s->tls);
        if (ret < 0) {
            error_report("TLS negotiation failed");
            return ret;
        }
        s->tls = NULL;
    }
    return 0;
}

static ssize_t read_server_options(Server *s) {
    char buf[1024];
    char *key, *val, *eq;
    int ret;

    while ((ret = safe_read(s->sockfd, buf, sizeof(buf) - 1)) > 0) {
        buf[ret] = '\0';
        for (char *p = buf; p && *p; p++) {
            if (*p == '\n') {
                *p = '\0';
                key = strtok_r(p + 1, "=", &val);
                if (key && *key && (eq = strchr(key, '\0')) && *(eq + 1)) {
                    *eq = '\0';
                    val = strtok_r(NULL, "\n", &val);
                    if (!strcmp(key, "opt")) {
                        ret = server_opt(s, val);
                    } else if (!strcmp(key, "cancel")) {
                        s->cancel = 1;
                    } else {
                        error_report("unknown server option: %s", key);
                    }
                }
                p = NULL;
            }
        }
    }
    if (ret < 0 && errno != EAGAIN) {
        error_report("Failed to read server options: %s",
                     strerror(errno));
        return ret;
    }
    return 0;
}
