#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <assert.h>
#include "test.h"
#include "hiredis.h"

#define REDIS_READER_MAX 1024

struct test_reply_reader_ctx {
    redisReader *r;
    char *buffer;
};

static void test_reply_reader_init(struct test_reply_reader_ctx *ctx) {
    ctx->buffer = malloc(REDIS_READER_MAX);
    ctx->r = redisReaderCreateWithMaxBufferLength(ctx->buffer, REDIS_READER_MAX);
    assert(ctx->r != NULL);
}

static void test_reply_reader_free(struct test_reply_reader_ctx *ctx) {
    redisReaderFree(ctx->r);
    free(ctx->buffer);
}

static void test_reader_string_reply(struct test_reply_reader_ctx *ctx) {
    const char *expected = "Hello World!";
    test_read(ctx->r, "+%s\r\n", expected);
    assert(replytype(ctx->r) == REDIS_REPLY_STRING);
    assert(strcmp(replystring(ctx->r), expected) == 0);
    test_reply_reader_free(ctx);
}

static void test_reader_int_reply(struct test_reply_reader_ctx *ctx) {
    test_read(ctx->r, ":12345\r\n");
    assert(replytype(ctx->r) == REDIS_REPLY_INTEGER);
    assert(replyinteger(ctx->r) == 12345);
    test_reply_reader_free(ctx);
}

static void test_reader_error_reply(struct test_reply_reader_ctx *ctx) {
    test_read(ctx->r, "-Error Message\r\n");
    assert(replytype(ctx->r) == REDIS_REPLY_ERROR);
    assert(strcmp(replystring(ctx->r), "Error Message") == 0);
    test_reply_reader_free(ctx);
}

static void test_reader_bulk_reply(struct test_reply_reader_ctx *ctx) {
    const char *expected = "Bulk data";
    test_read(ctx->r, "$%zu\r\n%s\r\n", strlen(expected), expected);
    assert(replytype(ctx->r) == REDIS_REPLY_STRING);
    assert(strcmp(replystring(ctx->r), expected) == 0);
    test_reply_reader_free(ctx);
}
