#include <windows.h>
#include <iostream>
#include <string>

// Function to install a Windows service
std::string installService(const std::string& filePath, const std::string& displayName) {
    SC_HANDLE schSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_CREATE_SERVICE);
    if (!schSCManager) {
        return "OpenSCManager failed: " + std::to_string(GetLastError());
    }
    SC_HANDLE schService = CreateService(
        schSCManager,
        filePath.c_str(),
        displayName.c_str(),
        SERVICE_ALL_ACCESS,
        SERVICE_WIN32_OWN_PROCESS,
        SERVICE_AUTO_START,
        SERVICE_ERROR_RESTART,
        filePath.c_str(),
        NULL, NULL, NULL, NULL, NULL
    );
    CloseServiceHandle(schSCManager);
    if (!schService) {
        std::string error = "CreateService failed: " + std::to_string(GetLastError());
        CloseServiceHandle(schService);
        return error;
    }
    CloseServiceHandle(schService);
    return "Service installed successfully";
}

// Function to remove a Windows service
std::string removeService(const std::string& serviceName) {
    SC_HANDLE schSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_CREATE_SERVICE);
    if (!schSCManager) {
        return "OpenSCManager failed: " + std::to_string(GetLastError());
    }
    SC_HANDLE schService = OpenService(schSCManager, serviceName.c_str(), DELETE);
    if (!schService) {
        CloseServiceHandle(schSCManager);
        return "OpenService failed: " + std::to_string(GetLastError());
    }
    if (!DeleteService(schService)) {
        CloseServiceHandle(schService);
        CloseServiceHandle(schSCManager);
        return "DeleteService failed: " + std::to_string(GetLastError());
    }
    CloseServiceHandle(schService);
    CloseServiceHandle(schSCManager);
    return "Service removed successfully";
}

