#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Function to set the directory path from the executable path
static int set_own_dir(char *buffer, size_t buf_len, const char *path) {
    size_t len = strlen(path);
    char *last_slash = strrchr(path, '/');
    if (!last_slash || last_slash == path) {
        errno = ENOENT;  // No directory separator found or at the start
        return -1;
    }
    if (len + 1 >= buf_len) {
        errno = ENAMETOOLONG;  // Buffer too small
        return -1;
    }
    memcpy(buffer, path, last_slash - path + 1);
    buffer[last_slash - path + 1] = '\0';
    return 0;
}

// Function to get the program's directory path
char *get_program_path(void) {
    char *executable_path = get_executable_path();
    if (!executable_path) {
        return NULL;
    }
    char *ret = malloc(strlen(executable_path) + 1);
    if (!ret) {
        free(executable_path);
        return NULL;
    }
    if (set_own_dir(ret, strlen(executable_path) + 1, executable_path) == 0) {
        free(executable_path);
        return ret;
    }
    free(ret);
    free(executable_path);
    return NULL;
}
