class WebServer {
public:
    struct Config {
        std::string sslCertPath;
        std::string sslKeyPath;
        bool enableSSL;
    };

    WebServer(const Config& config) : config_(config) {
        initializeSSL();
    }

private:
    Config config_;

    void initializeSSL() {
        struct mg_mgr mgr;
        mg_mgr_init(&mgr);
        struct mg_connection* nc = mg_bind_opt(&mgr, ":8443", &mg_http_server_opts, nullptr);
        if (!nc) {
            std::cerr << "Failed to start SSL server: port 8443 is in use or not available." << std::endl;
            mg_mgr_free(&mgr);
            throw std::runtime_error("Failed to initialize SSL server");
        }
        if (!config_.sslCertPath.empty() && !config_.sslKeyPath.empty()) {
            mg_set_ssl(nc, config_.sslCertPath.c_str(), config_.sslKeyPath.c_str(), nullptr, nullptr);
        } else {
            std::cerr << "SSL certificate and key paths must be provided if SSL is enabled." << std::endl;
            mg_mgr_free(&mgr);
            throw std::runtime_error("Incomplete SSL configuration");
        }
        mg_mgr_free(&mgr);
    }
};
